// 1. Array vazio [] — roda APENAS no mount (uma vez)
useEffect(() => {
  console.log('Componente montou!');
  fetchUserData();
}, []);

// 2. Com dependências [count] — roda quando 'count' muda
useEffect(() => {
  document.title = `Cliques: ${count}`;
}, [count]);

// 3. Sem array — roda em TODA renderização (evite!)
useEffect(() => {
  console.log('Renderizou'); // isso roda MUITO
});

import { useState, useEffect } from 'react';

function UserProfile({ userId }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    setLoading(true);
    fetch(`/api/users/${userId}`)
      .then(res => res.json())
      .then(data => {
        setUser(data);
        setLoading(false);
      });
  }, [userId]); // re-busca quando userId muda

  if (loading) return <p>Carregando...</p>;
  return <h1>{user.name}</h1>;
}

// ❌ Problema: options é um NOVO objeto a cada render
function Chat({ roomId }) {
  const options = { serverUrl: 'https://chat.example.com', roomId };

  useEffect(() => {
    const conn = createConnection(options);
    conn.connect();
    return () => conn.disconnect();
  }, [options]); // reconecta em TODA renderização!
}

// ✅ Solução: mova o objeto para DENTRO do efeito
function Chat({ roomId }) {
  useEffect(() => {
    const options = { serverUrl: 'https://chat.example.com', roomId };
    const conn = createConnection(options);
    conn.connect();
    return () => conn.disconnect();
  }, [roomId]); // reconecta só quando roomId muda
}

// ❌ Stale closure: count nunca atualiza dentro do interval
useEffect(() => {
  const id = setInterval(() => {
    console.log(count); // sempre mostra o valor inicial!
  }, 1000);
  return () => clearInterval(id);
}, []); // count não está nas dependências

// ✅ Corrigido: usar função atualizadora do setState
useEffect(() => {
  const id = setInterval(() => {
    setCount(c => c + 1); // não depende de count externo
  }, 1000);
  return () => clearInterval(id);
}, []); // agora está correto sem count nas deps
